var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":"우리는 황금나무의 예언을 받드는 낙원의 사도-","JPN":"我らは黄金の木の予言に従う楽園の使徒……","ENG":"We are the Apostles of the Promised Land who serve the prophecy of the Golden Tree.","TWN":"我們是守護黃金樹預言的樂園使徒—"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":"하늘이 갈라지고 어둠이 내려앉아도, 우리는 변함없이 기도하리라.","JPN":"天が裂かれ暗闇が訪れるとしても、我らは変わらず祈ろう。","ENG":"Even if the heavens split apart and darkness descends, we shall pray without faltering.","TWN":"即使天空分裂、黑暗降臨，我們仍會祈禱。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":"이 땅에 천사가 내려오고, 노랫소리가 울려 퍼지면, 우리의 정적 또한 심판 받을 지니.","JPN":"この地に天使が降り立ち、歌声が響けば、我らの政敵もまた審判されよう。","ENG":"When angels descend upon this land and song echoes through the air, our foe shall face judgment as well.","TWN":"當天使降臨這片土地、歌聲響起時，我們的寂靜也將受到審判。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":"우리가 비원을 이루는 그날- 가을 끝무렵의 침묵 속에서, 비로소 낙원은 완성되리라.","JPN":"我らの悲願が叶うその日……晩秋の沈黙の中で、ついに楽園は完成されるだろう。","ENG":"On the day our wish is fulfilled. Within the silence at the end of autumn, the Promised Land shall at last be complete.","TWN":"在我們願望實現的那一天—樂園終將在秋末的沉默中完成。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"영겁 끝에 맞닥뜨리게 될 첫눈을 맞으며-","JPN":"永劫の果てに迎える初雪とともに……","ENG":"As we welcome the first snowfall we will encounter at the end of eternity...","TWN":"在永恆之終迎來的第一場雪—"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"낙원의 약속은, 그렇게 이루어지리라.","JPN":"楽園の約束は、そうして叶うだろう。","ENG":"Thus shall the promise of the Promised Land be fulfilled.","TWN":"將如此實現樂園的承諾。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신이... 벌레 아저씨?","JPN":"あなたが……デレおじさん？","ENG":"Are you... Mr. Belly?","TWN":"你是……蟲子大叔？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":"하하, 사소한 오해가 있었나 보군요.","JPN":"はは、少々誤解があったようですね。","ENG":"Haha, it seems there's been a small misunderstanding.","TWN":"哈哈，看來有點小誤會。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"저는 벨레스라고 합니다. 황금나무를 모시는 사제장으로서, 도시 아나필리스의 크고 작은 일들을 거들고 있죠.","JPN":"私はヴェレスと申します。黄金の木に仕える司祭長として、この街、アナピリスの様々な仕事を手伝っています。","ENG":"My name is Veles. As the Krivi, the high priest who serves the Golden Tree, I help oversee the affairs of the city of Anapilis.","TWN":"我叫貝雷斯。身為黃金樹的祭司長，協助阿納菲莉絲城市的大大小小事務。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"벨레스 씨... 였군요.","JPN":"ヴェレスさん……だったんですね。","ENG":"Veles... I see.","TWN":"原來是……貝雷斯啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하긴, 사람 이름이 벌레일 리가 없는데... 저도 참 경황이 없네요.","JPN":"確かに、人の名前が「デレ」なわけないですよね……どうかしていました。","ENG":"Well, I suppose no one would actually be named \\"Belly\\"... I must be a bit out of sorts.","TWN":"也對，人的名字怎麼會叫蟲子嘛……我也真是太慌亂了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"이해합니다. 클라라도 아직 낙원에 한창 적응해나가는 시기니까요.","JPN":"分かります。クララもまだ楽園に適応している最中ですから。","ENG":"Understandable. Clara is still adjusting to life in the Promised Land.","TWN":"我理解。克拉拉還在適應樂園的生活呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"클라라... 그 아이 이름이구나.","JPN":"クララ……あの子のことですね。","ENG":"Clara... So that's the girl's name.","TWN":"克拉拉……原來那孩子叫這個名字啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"외지 사람이 이곳에 오게 되는 일은 그리 흔치 않답니다.","JPN":"外の人がここに来ることは滅多にないのです。","ENG":"It's not very common for outsiders to arrive here.","TWN":"外地人來到這裡的事並不常見。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"황금나무의 의지가 당신을 이곳으로 인도한 셈이죠.","JPN":"黄金の木の意志が、あなたをここに導いたのでしょう。","ENG":"It seems the will of the Golden Tree has guided you to this place.","TWN":"黃金樹的意志將你引導至此。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"황금나무라면... 저 커다란 나무를 말하는 건가?","JPN":"黄金の木って……あの大きな木のこと？","ENG":"The Golden Tree... Does he mean that enormous tree?","TWN":"黃金樹……是指那棵大樹嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"한 번도 본 적 없는 풍경이지만, 왠지 낯설지가 않아.","JPN":"初めて見る景色だけど、なんだか懐かしい。","ENG":"I've never seen scenery like this before, and yet it somehow doesn't feel unfamiliar.","TWN":"雖然我從未見過，但總覺得不陌生。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아나필리스라는 도시는 위치가 정확히 어떻게 되죠?","JPN":"アナピリスという街は、どこに位置しているのですか？","ENG":"Where exactly is the city called Anapilis located?","TWN":"阿納菲莉絲這個城市的具體位置在哪裡呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"아나필리스는 그 어디와도 이어져 있지 않습니다.","JPN":"アナピリスは他のどことも繋がっていません。","ENG":"Anapilis is not connected to anywhere.","TWN":"阿納菲莉絲不與任何地方相連。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그러니 장소를 특정 하는 것은 무의미하답니다.","JPN":"ですので、場所を特定することは意味のないことです。","ENG":"Which makes specifying its location rather meaningless.","TWN":"所以定位毫無意義。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하하... 수수께끼도 좋은데 진짜 정보를 들려주시면 안 될까요?","JPN":"はは……なぞなぞもいいですが、本当の情報を聞かせてもらえませんか？","ENG":"Haha... Riddles are nice and all, but could you tell me something real instead?","TWN":"哈哈……謎語很有趣，但能給我點真正的情報嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어쩌다 보니 신세를 지게 됐지만, 계속 여기 머물 순 없어서요.","JPN":"たまたまお世話になってはいますけど、ずっとここにいるわけにもいかないので。","ENG":"I ended up relying on your kindness, but I can't stay here forever.","TWN":"雖然因緣際會欠了你們人情，但我不能一直待在這裡。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"달리, 이곳을 떠나야 할 용무라도 있습니까?","JPN":"ここを離れなければいけない用事でもあるのですか？","ENG":"Is there some reason you must leave this place?","TWN":"你還有其他事需要離開這裡嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그건...","JPN":"それは……","ENG":"That's...","TWN":"那個……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어...?","JPN":"あれ……？","ENG":"Huh...?","TWN":"嗯……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"타기리온을 막으려던 것까진 기억이 나는데...","JPN":"タギリオンを止めようとしたことまでは覚えているのに……","ENG":"I remember trying to stop Thagirion...","TWN":"我有阻止塔基里翁的記憶……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그 뒤의 일은 왜 이렇게 어렴풋하지?","JPN":"……その後の事はどうしてこんなにぼんやりしてるんだろう？","ENG":"...But why is everything after that so hazy?","TWN":"……但之後發生的事情怎麼這麼模糊？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"지금까지 있었던 기억이 마치... 전부 꿈이었던 것처럼 아득해.","JPN":"今までの記憶がまるで……全部夢の中で起こったことのようにはっきりしない。","ENG":"Everything that's happened up until now feels like... it was all just a dream.","TWN":"到現在的記憶……都好像是作夢一樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"타기리온을 마주한 게 현실이라면, 몸 멀쩡히 침대에서 깨어나는 건 설명이 안 되지 않나?","JPN":"タギリオンに会ったのが現実なら、傷一つない状態でベッドで目覚めた説明がつかない。","ENG":"If facing Thagirion was real, then waking up unharmed in a bed makes no sense.","TWN":"如果面對塔基里翁是現實，那我為什麼會毫髮無傷地在床上醒來呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아...!","JPN":"あ……！","ENG":"Ah...!","TWN":"啊……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"왜 그러시죠?","JPN":"どうされましたか？","ENG":"Is something wrong?","TWN":"你怎麼了？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"저와 같이 있던 금발 여자는 혹시...!","JPN":"私と一緒にいた金髪の女は……！","ENG":"The blonde woman who was with me! Could she be–!","TWN":"和我在一起的金髮女子難道是……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"윽?","JPN":"くっ？","ENG":"Ngh?","TWN":"唔？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"이런. 상처가 터졌군요.","JPN":"やれやれ。傷口が開いてしまいましたね。","ENG":"Oh dear. Your wound has reopened.","TWN":"哎呀，傷口裂開了呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"치료한 지 얼마 안 됐으니 좀 더 조심하라고 말씀드렸어야 했는데, 제 불찰입니다.","JPN":"治療して間もないので、もっと気をつけた方がいいとお伝えするべきだったのですが、私の手落ちです。","ENG":"I should have warned you to be more careful since it hasn't been long since you were treated. My mistake.","TWN":"治療後要更小心一點，我應該早點提醒你才對，是我疏忽了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"나한테... 상처가...?","JPN":"私に……傷が……？","ENG":"I have... a wound...?","TWN":"我的……傷口……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"이곳에 오기 전에 큰 다툼이 있었던 모양이군요.","JPN":"ここにいらっしゃる前に激しい戦いをされたのでしょう。","ENG":"It seems you were involved in quite a battle before arriving here.","TWN":"你在來這裡之前，好像經歷了一場激烈的戰鬥。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"하지만 이젠 걱정 마시길. 이곳 아나필리스에선 누구도 원치 않는 싸움 같은 건 벌어지지 않으니까요.","JPN":"ですが、もう心配いりません。ここ、アナピリスでは誰でも望まぬ戦いなど起こしませんから。","ENG":"But please, rest assured. In Anapilis, no one engages in battles they do not wish for.","TWN":"不過你現在不用擔心。在阿納菲莉絲這裡，沒有人會發動不必要的戰爭。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"난... 다시 돌아가야...","JPN":"私……帰らないと……","ENG":"I... need to go back...","TWN":"我……必須回去……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_WATER"},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_GIRL_QM","text":{"KOREA":"앗.","JPN":"あっ。","ENG":"Ah.","TWN":"啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_GIRL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_GIRL_QM","text":{"KOREA":"괜찮으신 겁니까? 그분.","JPN":"大丈夫なのですか？　その方。","ENG":"Is she all right?","TWN":"那位沒事吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_GIRL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"...그래.","JPN":"……ああ。","ENG":"...Yes.","TWN":"……嗯。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"하지만 다시 침소로 옮겨 상처를 돌봐야겠구나.","JPN":"けど、また寝室に運んで傷口を看ないといけないね。","ENG":"But we should move her back to her room and tend to the wound again.","TWN":"但該回床上好好照料傷口了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"좀 도와주겠니? 에클레시아.","JPN":"少し手伝ってくれるかい？　エクレシア。","ENG":"Would you lend a hand, Ecclesia?","TWN":"你能幫我嗎？艾可露西亞。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...예.","JPN":"……はい。","ENG":"...Yes.","TWN":"……是。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아버지.","JPN":"お父様。","ENG":"Father.","TWN":"父親。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"......마, 렴.","JPN":" ……ない、で。","ENG":"–ry...","TWN":"……哭。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"음......?","JPN":" うん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"HARMONY2_04","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"울지, 마렴....","JPN":" 泣か、ないで……","ENG":"Don't... cry...","TWN":"不要…哭……"},"stage":{"bg":"HARMONY2_04","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"......아.","JPN":" …………あ。","ENG":"...Ah.","TWN":"……啊。"},"stage":{"bg":"HARMONY2_04","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"죽여 버렸네요.","JPN":" 殺してしまいましたね。","ENG":"I killed her.","TWN":"死掉了。"},"stage":{"bg":"HARMONY2_04","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"......정말로.","JPN":" ……本当に。","ENG":"...I really.","TWN":"真的……。"},"stage":{"bg":"HARMONY2_04","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"정말로, 죽여 버렸어요.","JPN":" 本当に、殺してしまいました。","ENG":"I really... killed her.","TWN":"真的，死掉了。"},"stage":{"bg":"HARMONY2_04","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"마에스트로 네퀴티아의 기억.","JPN":"マエストロ・ネキティアの記憶。","ENG":"The memories of Maestra Nequitia.","TWN":"指揮家莉奎蒂亞的記憶"},"stage":{"bg":"HARMONY2_04","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"나와 뒤섞인 그 여자의 마지막 악행이... 밤마다 악몽이 되어 되풀이된다.","JPN":"私の中に入り混じったあの女、その最後の悪行が……毎晩、悪夢として繰り返される。","ENG":"Her final atrocity, now intertwined with me... returns every night as a nightmare.","TWN":"那個與我交織的女人最後的惡行……每晚都會化作惡夢重演。"},"stage":{"bg":"HARMONY2_04","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"내가 저지른 일이 아님에도, 어머니를 죽인 타인의 손길이 마치 내 것인 것처럼, 생생하다.","JPN":"自分はやっていないのに、お母さんを殺した他人の手がまるで自分の手のように生々しく感じられる。","ENG":"Even though it wasn't my deed, the hands that killed my mother feel as vivid as if they were my own.","TWN":"即便那不是我做的事，卻感覺那雙殺死母親的手就是我自己的。"},"stage":{"bg":"HARMONY2_04","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"한 번 죽은 사람은 돌아오지 않아.","JPN":"死んでしまった人が戻ってくることはない。","ENG":"Once someone dies, they never come back.","TWN":"死去的人，不會復生。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"그런 당연한 전제 하나가 우리의 경험과 뇌리에 박혀있지.","JPN":"そんな当たり前の前提ひとつが、私たちの経験と脳裏に刻まれている。","ENG":"That simple premise is carved into our experience and our minds.","TWN":"這樣再當然不過的前提，深植於我們的經驗與記憶中。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"그럼으로서 살인은 무거운 죄악이 되고, 후회는 무의미해져.","JPN":"それにより殺人は重い罪悪となり、後悔は意味をなくす。","ENG":"Because of that, murder becomes a grave sin and regret becomes meaningless.","TWN":"因此殺人是重罪，而悔恨毫無意義。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"알고 있었어.","JPN":"分かってた。","ENG":"I knew it.","TWN":"我早就明白了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"나라를 위해 내 어머니의 삶을 송두리째 망가뜨린 반군의 복수와...","JPN":"国のためにと言いながらお母さんの人生すべてを滅茶苦茶にした反乱軍の復讐と……","ENG":"The rebels' revenge, carried out in the name of their country, which ruined my mother's life...","TWN":"為了國家，徹底毀了我母親一生的反抗軍的復仇……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"나라를 위해 그런 쓰레기 같은 반군을 죽여야 했던 나의 복수는...","JPN":"国のためにと言いながらゲスのような反乱軍を殺した私の復讐は……","ENG":"And my revenge, carried out in the name of my country, which forced me to kill those wretched rebels...","TWN":"以及我必須為了國家，殺死那些有如垃圾的反抗軍的復仇……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"별반 다르지 않은 죄악이자, 후회가 될 거라는 걸.","JPN":"大した違いのない罪悪であり、後で後悔するってことを。","ENG":"They are both sins of no real difference, and regrets all the same.","TWN":"這兩者本質上都一樣是罪孽，也都會讓人後悔。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"인과응보나 카르마 같은 표현은... 그저, 그런 당연한 섭리를 포장하는 방식에 지나지 않아.","JPN":"因果応報やカルマといった表現は……ただ、そんな当たり前の摂理をもっともらしく言っているだけ。","ENG":"Expressions like cause and effect or karma... are merely ways of dressing up that simple truth.","TWN":"什麼因果報應、業力之類的說法……不過是包裝這種理所當然道理的方式罷了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"그런 당연한 사실을...","JPN":"そんな当たり前の事実を……","ENG":"Such an obvious truth...","TWN":"為什麼總要等一切結束後才能謙卑接受……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"왜 모든 일이 끝나고 나서야 겸허히 받아들이게 되는 걸까.","JPN":"どうしてすべてが終わる前に、謙虚に受け入れられなかったんだろう。","ENG":"Why do we only accept it humbly after everything is already over?","TWN":"這種理所當然的事呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"...그럴 수는 없겠지만...","JPN":"……できないとは分かってはいるけど……","ENG":"...It's impossible, but...","TWN":"……雖然不可能……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"모든 걸 처음으로 되돌릴 수만 있다면...","JPN":"すべてを最初に戻すことができるなら……","ENG":"If everything could be returned to the beginning...","TWN":"若一切能回到原點……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"나는...","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"익숙한 천장이네.","JPN":"見慣れた天井だ。","ENG":"It's that ceiling again.","TWN":"這熟悉的天花板。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"다시 돌아온 건가.","JPN":"戻ってきたのかな。","ENG":"So I came back.","TWN":"我回來了嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"OLD_GRONIA_NULL_QM","text":{"KOREA":"괜찮니, 아가?","JPN":"大丈夫かい？　レア。","ENG":"Are you all right, my dear?","TWN":"你還好嗎，孩子？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"왜...","JPN":"どうして……","ENG":"Why...","TWN":"為什麼……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"엄마가 왜 여기에...?","JPN":"お母さんが、どうしてここに……？","ENG":"Why is Mom here...?","TWN":"媽媽怎麼會在這裡……？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"악몽을 꿨나 보구나.","JPN":"悪夢を見たようね。","ENG":"You must have had a nightmare.","TWN":"看來你做噩夢了呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"하지만 괜찮아. 이곳에선 그런 악몽 같은 일, 다시는 일어나지 않을 테니까.","JPN":"でも、大丈夫。ここではそんな悪夢のようなことは、二度と起きないから。","ENG":"But it's all right. In this place, things like those nightmares will never happen again.","TWN":"不過沒關係，在這裡不會再發生那種惡夢般的事了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"악몽이라고요? 지금까지 있었던 이 모든 게...?","JPN":"悪夢？　今までのことすべて……？","ENG":"A nightmare? Everything that happened until now... was that all...?","TWN":"惡夢？剛才發生的這一切都是夢……？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"...긴 연주회였지.","JPN":"……長い演奏会だったわね。","ENG":"...It was a long recital.","TWN":"……算是一場長長的演奏吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"하지만 이젠 악기를 내려놓고, 함께 이 고요함을 즐기자꾸나.","JPN":"でももう楽器は置いて、一緒にこの静けさを楽しみましょう。","ENG":"But now, set the instrument down and enjoy this quiet with me.","TWN":"但現在可以放下樂器，一起享受這份寧靜了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"역시... 엄마의 품은 포근하네요.","JPN":"やっぱり……お母さんの腕の中は暖かいね。","ENG":"Just like I remember... Mom's embrace is warm.","TWN":"果然……媽媽的懷抱好溫暖。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이렇게 진짜 같은 꿈이라면, 얼마든지 꿔도 좋을 거에요.","JPN":"こういう現実味のある夢なら、何度でも見たいな。","ENG":"If it's a dream this real, I wouldn't mind dreaming it forever.","TWN":"如果是這麼真實的夢，我可以一直待下去。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"말했잖니. 이건 꿈이 아니라고.","JPN":"言ったでしょう？　これは夢じゃないのよ。","ENG":"I told you, it's not a dream.","TWN":"我說過了，這不是夢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그저 꿈이었다고 외면하기엔 너무 많은 사람이 죽었어요.","JPN":"夢だったって無視するには、あまりにも多くの人が亡くなったの。","ENG":"Too many people died for me to dismiss it all as just a dream.","TWN":"如果說這只是夢，有太多無辜的人死去了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"이곳에서 죽음은 아무런 의미가 없어.","JPN":"ここでは死は何の意味も持たない。","ENG":"In this place, death carries no meaning.","TWN":"在這裡，死亡毫無意義。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그렇기 때문에 복수도, 후회도 필요로 하지 않지.","JPN":"だから復讐も、後悔も必要ないのよ。","ENG":"Which is why neither revenge nor regret is necessary.","TWN":"所以不需要復仇，也不需要後悔。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그런 걸 현실이라고 부를 수 있을까요?","JPN":"そんなもの現実って呼べる？","ENG":"Can something like that really be called reality?","TWN":"那這能算是現實嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"적어도 꿈은 아니지.","JPN":"少なくとも夢ではないわ。","ENG":"At the very least, it isn't a dream.","TWN":"至少不是夢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"깨고 나면 아무것도 잡히지 않는, 그런 허황된 꿈은 아니야.","JPN":"目覚めたら何も残らない、そんな虚しい夢じゃないの。","ENG":"Not a fleeting dream that leaves you with nothing once you wake.","TWN":"這裡不是醒來後什麼也抓不到的虛幻夢境。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어째서죠?","JPN":"どうして？","ENG":"Why not?","TWN":"為什麼呢？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이런 좋은 일은... 저처럼 죄를 지은 사람에겐 있어선 안되는 기적일 텐데...","JPN":"こんな良いこと……私みたいな罪深い人間にあっちゃいけない奇跡のはず……","ENG":"Something this good... feels like a miracle someone like me, who has sinned, should never receive.","TWN":"這種美好的事……這種奇蹟不會發生在我這種有罪的人身上……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"낙원은 네가 누구든 차별하지 않는단다.","JPN":"楽園はあなたがどんな人でも差別しないわ。","ENG":"The Promised Land does not discriminate based on who you are.","TWN":"樂園不會歧視任何人。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그것이 이곳의 섭리이니까.","JPN":"それがここの摂理だもの。","ENG":"That is the law of this place.","TWN":"這就是這裡的法則。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"낙원... 이라고요?","JPN":"楽園って……？","ENG":"The Promised Land...?","TWN":"樂園……嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"몇 월 같은 거 없어. 여긴 낙원이니까.","JPN":"何月とか、そんなのないよ。ここは楽園だから。","ENG":"There's no such thing as months. This is the Promised Land.","TWN":"這裡是樂園，沒有月份這種東西。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"매일매일이 똑같은 날이거든요.","JPN":"毎日毎日、同じ日。","ENG":"Every day is the same day here.","TWN":"因為每天都是一樣的日子。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"사후세계라고 해서 기대했던 것만큼 가혹하진 않네요.","JPN":"死後の世界って、期待していたほど過酷じゃないのね。","ENG":"For an afterlife, it's not nearly as harsh as I expected.","TWN":"原來所謂的來世，並不像我想像得那麼殘酷。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"악인은 죽어서 악인다운 대가를 치를 거라 생각했는데, 이건 너무 평화롭잖아요.","JPN":"死んだら悪人は悪人に見合った償いがあると思っていたのに、これじゃ平和過ぎるよ。","ENG":"I thought evil people would die and receive the punishment they deserved. But this place is too peaceful.","TWN":"我以為惡人死後會得到應有的懲罰，結果這裡太和平了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"모든 사람이 낙원에 다다를 수 있는 건 아니란다.","JPN":"全員が楽園にたどり着けるわけじゃないのよ。","ENG":"Not everyone can reach the Promised Land.","TWN":"不是每個人都能抵達樂園。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"하지만 우리가 이곳에 있는 이유는 나도, 너도, 하물며 신도 알지 못해.","JPN":"でも私たちがここにいる理由は私も、あなたも、それに神様だって分からないわ。","ENG":"But why we are here... Neither you, nor I, nor even god knows.","TWN":"但我也不知道、你也不知道，甚至神也不知道我們在這裡的原因。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"지금으로선... 네가 이곳을 마음에 들어했으면 하는 바람 뿐이구나.","JPN":"今は……あなたがここを気に入ってくれればいいと願うだけよ。","ENG":"For now... all I wish is that you come to like this place.","TWN":"現在……我只希望你喜歡這裡。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"마음에 안 들 리가 없잖아요.","JPN":"気に入らないわけないじゃない。","ENG":"How could I not?","TWN":"我怎麼會不喜歡呢？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"다신 못 만날 줄 알았던 우리 엄마를, 이렇게 다시 만났는데.","JPN":"二度と会えないと思ってたお母さんに、こうしてまた会えたんだから。","ENG":"I've been reunited with my mother, whom I thought I would never see again.","TWN":"能再見到以為再也見不到的媽媽。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"나도 있어.","JPN":"私もいるよ。","ENG":"I'm here too.","TWN":"還有我。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"나도 다시 만나서 좋죠?","JPN":"私にもまた会えて嬉しいよね？","ENG":"You're happy to see me again too, right?","TWN":"你也很高興能再見到我吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"음? 넌...","JPN":"うん？　君は……","ENG":"Hmm? You're...","TWN":"嗯？你是……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"클라라, 맞지?","JPN":"クララだったよね？","ENG":"Clara, right?","TWN":"克拉拉，對吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"응, 그렇게 불러도 돼요.","JPN":"うん、そう呼んでくれてもいいよ。","ENG":"Yes, you can call me that.","TWN":"嗯，你可以這麼叫我。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"다시 만나서 반가워. 클라라.","JPN":"また会えてうれしいよ、クララ。","ENG":"It's nice to see you again, Clara.","TWN":"很高興再見到你，克拉拉。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"꽃을 엄청 많이 땄구나.","JPN":"花をたくさん摘んできたんだね。","ENG":"You picked so many flowers.","TWN":"你摘了好多花啊。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"응, 친구한테 주려고요.","JPN":"うん、友だちにあげたくて。","ENG":"They're for a friend.","TWN":"嗯，我打算送給朋友。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"같이 갈래요?","JPN":"一緒に行く？","ENG":"Would you like to come with me?","TWN":"要一起去嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};